<?php require __DIR__.'/../includes/bootstrap.php';require_admin();if(!booths_schema_ready())redirect('upgrade-booths-marketplace.php');if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$id=(int)$_POST['booth_id'];$status=$_POST['status']??'pending';$allowed=['pending','approved','rejected','suspended','archived'];if(in_array($status,$allowed,true))db()->prepare('UPDATE booths SET status=?,admin_notes=? WHERE id=?')->execute([$status,trim($_POST['admin_notes']??''),$id]);flash('success','Booth status updated.');redirect('admin/booths.php');}$booths=db()->query("SELECT b.*,u.display_name AS owner_name,c.name AS company_name,br.name AS brand_name,(SELECT COUNT(*) FROM booth_products p WHERE p.booth_id=b.id) products FROM booths b JOIN users u ON u.id=b.owner_user_id LEFT JOIN companies c ON c.id=b.company_id LEFT JOIN brands br ON br.id=b.brand_id ORDER BY FIELD(b.status,'pending','approved','rejected','suspended','archived'),b.created_at DESC")->fetchAll();app_header('Booth Administration');?>
<section class="dashboard-hero"><p class="eyebrow">ADMINISTRATION</p><h1>Booth Approvals</h1><p>Review exhibitors before they enter the public convention hall.</p></section><section class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Booth</th><th>Owner</th><th>Affiliation</th><th>Products</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach($booths as $b):?><tr><td><strong><?=e($b['name'])?></strong><br><small><?=e($b['tagline'])?></small></td><td><?=e($b['owner_name'])?></td><td><?=e($b['brand_name']?:$b['company_name']?:'Independent')?></td><td><?=$b['products']?></td><td><span class="status-badge <?=e($b['status'])?>"><?=e($b['status'])?></span></td><td><form method="post" class="inline-admin-form"><?=csrf_field()?><input type="hidden" name="booth_id" value="<?=$b['id']?>"><select name="status"><?php foreach(['pending','approved','rejected','suspended','archived'] as $st):?><option <?=$b['status']===$st?'selected':''?>><?=$st?></option><?php endforeach?></select><input name="admin_notes" value="<?=e($b['admin_notes'])?>" placeholder="Notes"><button class="button primary">Save</button></form></td></tr><?php endforeach?></tbody></table></section><?php app_footer();